#!/usr/bin/env perl

use strict;
use warnings;

my $log_dir = '/var/log';

my $filename = param('logfile');

open(FH, "$log_dir/$filename") or die "Unable to open file: $!";

while (<FH>) {
    print $_;
}

close(FH);